import axios from 'axios';

const API_BASE_URL = process.env.VUE_APP_API_BASE_URL || 'http://localhost:3000';

// Create axios instance with default config
const api = axios.create({
    baseURL: API_BASE_URL,
    headers: {
        'Content-Type': 'application/json'
    }
});

// Add token to requests
api.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// Get all subjects
export const getAllSubjects = async () => {
    try {
        const response = await api.get('/api/subjects');
        return response.data.data;
    } catch (error) {
        console.error('Error fetching subjects:', error);
        throw error;
    }
};

// Get subject by ID
export const getSubjectById = async (subjectId) => {
    try {
        const response = await api.get(`/api/subjects/${subjectId}`);
        return response.data.data;
    } catch (error) {
        console.error('Error fetching subject:', error);
        throw error;
    }
};

// Create new subject
export const createSubject = async (subjectData) => {
    try {
        const response = await api.post('/api/subjects', subjectData);
        return response.data.data;
    } catch (error) {
        console.error('Error creating subject:', error);
        throw error;
    }
};

// Update subject
export const updateSubject = async (subjectId, subjectData) => {
    try {
        const response = await api.put(`/api/subjects/${subjectId}`, subjectData);
        return response.data.data;
    } catch (error) {
        console.error('Error updating subject:', error);
        throw error;
    }
};

// Delete subject
export const deleteSubject = async (subjectId) => {
    try {
        const response = await api.delete(`/api/subjects/${subjectId}`);
        return response.data;
    } catch (error) {
        console.error('Error deleting subject:', error);
        throw error;
    }
};

export default {
    getAllSubjects,
    getSubjectById,
    createSubject,
    updateSubject,
    deleteSubject
};
